    await page.locator("button#add-to-cart, button[id^=\"add-to-cart\"], button:has-text('Add to cart')")
      .first()
      .click({ timeout: 10000 });


    await page.locator("#shopping_cart_container, a.shopping_cart_link, .shopping_cart_link")
      .first()
